mapper.select:
select type, id, frame, customer, time, number, total, actual, money as invoice_collection, money - actual as accounts_receivable_balance, (money / actual) * 100 as collection_rate, nucleus, data from ( select '销售单' as type, sell.id, frame.name as 'frame', customer.name as 'customer', sell.time, sell.number, sell.total, sell.actual, sell.money, sell.nucleus, sell.data
from sell left join frame on sell.frame = frame.id left join customer on sell.customer = customer.id where examine = 1
union all
select '销售退货单' as type, sre.id, frame.name as 'frame', customer.name as 'customer', sre.time, sre.number, sre.total, sre.actual, sre.money, sre.nucleus, sre.data
from sre left join frame on sre.frame = frame.id left join customer on sre.customer = customer.id where examine = 1 ) as sales_receipt
and customer like concat('%', #{query.customer}, '%')
and number = #{query.number}
and time >= #{query.begintime}
and time <= #{query.endtime}
and nucleus = #{query.nucleus}
and type = #{query.type}
order by time desc

